mapper.select:
SELECT
    id, tutor_id, subject_id, title, description, price_per_hour, mode, city, available_time,
    max_students, status, create_time, update_time
FROM teacher_job_posting
WHERE tutor_id = #{tutorId}

    AND id < #{cursor}

ORDER BY id DESC
LIMIT #{pageSize}

SELECT
    id, tutor_id, subject_id, title, description, price_per_hour, mode, city, available_time,
    max_students, status, create_time, update_time
FROM teacher_job_posting
WHERE status = 1

    AND subject_id = #{subjectId}


    AND mode = #{mode}


    AND city = #{city}


    AND id < #{cursor}

ORDER BY id DESC
LIMIT #{pageSize}
